    it('should prefer bureaus array over legacy bureau field', () => {
      const item: NegativeItem = {
        id: '1',
        creditor_name: 'Test',
        bureaus: ['experian'],
        bureau: 'transunion',
      };
      expect(itemAppearsOnBureau(item, 'experian')).toBe(true);
      expect(itemAppearsOnBureau(item, 'transunion')).toBe(false);
    });
  });
});

